/**
 * XPGem.js — 经验宝石与道具掉落物，带磁吸效果。
 */
const {Vector2} = require("/Users/fiona/Desktop/neon-survivors/js/utils/Vector2.js");
const {TAU} = require("/Users/fiona/Desktop/neon-survivors/js/utils/math.js");
